"use client";

import { motion } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";

type Props = {
  data: TeachingDataset;
  mode: "row" | "col";
  highlightIndices?: number[];
  accent: string;
};

export function VectorDisplay({ data, mode, highlightIndices = [], accent }: Props) {
  const items =
    mode === "row"
      ? data.rows.map((label, i) => ({
          label,
          vector: data.matrix[i],
          index: i,
        }))
      : data.cols.map((label, j) => ({
          label,
          vector: data.matrix.map((row) => row[j]),
          index: j,
        }));

  const dimLabel = mode === "row" ? data.colLabel : data.rowLabel;

  return (
    <div className="space-y-3">
      {items.map(({ label, vector, index }, i) => {
        const highlighted = highlightIndices.includes(index);
        return (
          <motion.div
            key={label}
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: i * 0.1 }}
            className="border-3 border-black p-3"
            style={{
              backgroundColor: highlighted ? `${accent}15` : "#FFF",
              boxShadow: highlighted ? `4px 4px 0 ${accent}` : "3px 3px 0 #0A0A0A",
            }}
          >
            <div className="flex flex-wrap items-center gap-2">
              <span
                className="border-2 border-black px-2 py-0.5 font-mono text-xs font-bold"
                style={{ backgroundColor: highlighted ? accent : "#F0F0F0", color: highlighted ? "#FFF" : "#0A0A0A" }}
              >
                {label}
              </span>
              <span className="font-mono text-xs text-black/50">=</span>
              <span className="font-mono text-sm font-bold">[</span>
              {vector.map((v, vi) => (
                <motion.span
                  key={vi}
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ delay: i * 0.1 + vi * 0.06 }}
                  className="border-2 border-black px-2 py-0.5 font-mono text-sm font-bold"
                  style={{
                    backgroundColor: v >= 4 ? accent : v <= 2 ? "#E8E8E8" : "#FFD23F",
                    color: v >= 4 ? "#FFF" : "#0A0A0A",
                  }}
                >
                  {v}
                </motion.span>
              ))}
              <span className="font-mono text-sm font-bold">]</span>
            </div>
            <p className="mt-1.5 font-mono text-[9px] uppercase tracking-widest text-black/40">
              {mode === "row"
                ? `One ${data.rowUnit} · ${vector.length} ${data.colUnit} ratings`
                : `One ${data.colUnit} · ratings from ${vector.length} ${data.rowUnit}s`}
            </p>
          </motion.div>
        );
      })}
      <p className="text-xs text-black/60">
        Each number is a rating along a <strong>{dimLabel}</strong> dimension.
      </p>
    </div>
  );
}
