"use client";

import { useMemo, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { DATASETS, getDataset } from "@/lib/datasets";
import { TEACHING_DATASETS } from "@/lib/lesson-data";
import {
  MODE_INFO,
  VIEW_MODES,
  buildHeatmapCells,
  starsLabel,
} from "@/lib/heatmap-utils";
import type { ViewMode } from "@/lib/types";
import { Heatmap } from "./Heatmap";
import { Slider } from "./Slider";
import { LessonWizard } from "./lesson/LessonWizard";

type Tab = "learn" | "explore";

export function ClusteringDashboard() {
  const [tab, setTab] = useState<Tab>("learn");
  const [datasetId, setDatasetId] = useState("movies");
  const [mode, setMode] = useState<ViewMode>("original");
  const [contrast, setContrast] = useState(1.3);
  const [noise, setNoise] = useState(0.03);

  const dataset = getDataset(datasetId);
  const teaching = TEACHING_DATASETS.find((d) => d.id === datasetId)!;

  const cells = useMemo(
    () => buildHeatmapCells(dataset, mode, noise),
    [dataset, mode, noise],
  );

  const miniViews = VIEW_MODES.map((m) => ({
    mode: m,
    cells: buildHeatmapCells(dataset, m, noise),
    info: MODE_INFO[m],
  }));

  return (
    <div className="min-h-screen bg-[#FFFDF7] text-black">
      <div
        className="pointer-events-none fixed right-0 top-0 h-full w-3"
        style={{
          background: `repeating-linear-gradient(-45deg, ${teaching.theme.accent}, ${teaching.theme.accent} 6px, transparent 6px, transparent 12px)`,
        }}
      />

      <div className="relative mx-auto max-w-6xl px-5 py-8 md:px-8">
        {/* Header */}
        <header className="mb-6 border-b-4 border-black pb-5">
          <p className="font-mono text-[10px] font-bold uppercase tracking-[0.25em] text-black/50">
            Visual Analytics · Exercise 5
          </p>
          <h1
            className="mt-1 text-4xl font-black uppercase tracking-tight md:text-5xl"
            style={{ color: teaching.theme.accent }}
          >
            Cluster Lab
          </h1>
          <p className="mt-2 max-w-xl text-sm font-medium text-black/60">
            Learn clustering step by step with real numbers, then explore full heatmaps.
          </p>

          {/* Tab switch */}
          <div className="mt-5 flex gap-0">
            {(["learn", "explore"] as Tab[]).map((t) => (
              <button
                key={t}
                onClick={() => setTab(t)}
                className="relative border-3 border-black px-6 py-2.5 font-mono text-xs font-bold uppercase"
                style={{
                  backgroundColor: tab === t ? teaching.theme.accent : "#FFF",
                  color: tab === t ? "#FFF" : "#0A0A0A",
                  marginRight: -3,
                  boxShadow: tab === t ? `4px 4px 0 #0A0A0A` : "none",
                  zIndex: tab === t ? 2 : 1,
                }}
              >
                {t === "learn" ? "① Learn step-by-step" : "② Explore heatmaps"}
              </button>
            ))}
          </div>
        </header>

        <AnimatePresence mode="wait">
          {tab === "learn" ? (
            <motion.div
              key="learn"
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
            >
              <LessonWizard datasetId={datasetId} onDatasetChange={setDatasetId} />

              {/* Quick dataset overview */}
              <div className="mt-6 grid gap-3 sm:grid-cols-3">
                {TEACHING_DATASETS.map((d) => (
                  <button
                    key={d.id}
                    onClick={() => setDatasetId(d.id)}
                    className="border-3 border-black p-3 text-left"
                    style={{
                      backgroundColor: datasetId === d.id ? d.theme.accentLight : "#FFF",
                      boxShadow: datasetId === d.id ? `4px 4px 0 ${d.theme.accent}` : "2px 2px 0 #0A0A0A",
                    }}
                  >
                    <p className="text-xs font-black uppercase">{d.title}</p>
                    <p className="mt-1 font-mono text-[9px] text-black/50">{starsLabel(d.stars)}</p>
                    <p className="mt-1 text-[10px] text-black/60">
                      {d.rowClusters[0].meaning.split("&")[0].trim()}…
                    </p>
                  </button>
                ))}
              </div>
            </motion.div>
          ) : (
            <motion.div
              key="explore"
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
              className="space-y-5"
            >
              <ExplorePanel
                datasetId={datasetId}
                onDatasetId={setDatasetId}
                dataset={dataset}
                mode={mode}
                onMode={setMode}
                contrast={contrast}
                onContrast={setContrast}
                noise={noise}
                onNoise={setNoise}
                cells={cells}
                miniViews={miniViews}
              />
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

function ExplorePanel({
  datasetId,
  onDatasetId,
  dataset,
  mode,
  onMode,
  contrast,
  onContrast,
  noise,
  onNoise,
  cells,
  miniViews,
}: {
  datasetId: string;
  onDatasetId: (id: string) => void;
  dataset: ReturnType<typeof getDataset>;
  mode: ViewMode;
  onMode: (m: ViewMode) => void;
  contrast: number;
  onContrast: (v: number) => void;
  noise: number;
  onNoise: (v: number) => void;
  cells: ReturnType<typeof buildHeatmapCells>;
  miniViews: { mode: ViewMode; cells: ReturnType<typeof buildHeatmapCells>; info: (typeof MODE_INFO)[ViewMode] }[];
}) {
  const info = MODE_INFO[mode];

  return (
    <>
      <div className="flex flex-wrap gap-2">
        {DATASETS.map((d) => (
          <button
            key={d.id}
            onClick={() => onDatasetId(d.id)}
            className="border-2 border-black px-3 py-1.5 font-mono text-[10px] font-bold uppercase"
            style={{
              backgroundColor: datasetId === d.id ? d.theme.accent : "#FFF",
              color: datasetId === d.id ? "#FFF" : "#0A0A0A",
            }}
          >
            {d.title}
          </button>
        ))}
      </div>

      <div className="grid gap-5 lg:grid-cols-[220px_1fr]">
        <aside className="space-y-3">
          <div className="border-3 border-black bg-white p-3" style={{ boxShadow: `4px 4px 0 ${dataset.theme.accent}` }}>
            <p className="mb-2 font-mono text-[9px] font-bold uppercase text-black/40">Mode</p>
            {VIEW_MODES.map((m) => (
              <button
                key={m}
                onClick={() => onMode(m)}
                className="mb-1 w-full px-2 py-2 text-left font-mono text-[10px] font-bold uppercase"
                style={{
                  backgroundColor: mode === m ? dataset.theme.accent : "transparent",
                  color: mode === m ? "#FFF" : "#0A0A0A",
                }}
              >
                {MODE_INFO[m].title}
              </button>
            ))}
          </div>
          <div className="border-3 border-black bg-white p-3" style={{ boxShadow: "3px 3px 0 #0A0A0A" }}>
            <Slider label="Contrast" value={contrast} min={0.7} max={2.5} step={0.1} accent={dataset.theme.accent} onChange={onContrast} format={(v) => `${v.toFixed(1)}×`} />
            <div className="mt-4">
              <Slider label="Noise" value={noise} min={0} max={0.18} step={0.01} accent={dataset.theme.secondary} onChange={onNoise} format={(v) => `${(v * 100).toFixed(0)}%`} />
            </div>
          </div>
        </aside>

        <div className="border-3 border-black bg-white" style={{ boxShadow: `6px 6px 0 ${dataset.theme.accent}` }}>
          <div className="border-b-3 border-black px-5 py-3" style={{ backgroundColor: dataset.theme.accentLight }}>
            <p className="text-sm font-black uppercase">{dataset.title}</p>
            <p className="text-xs text-black/60">{info.subtitle}</p>
          </div>
          <div className="flex justify-center overflow-x-auto p-6">
            <Heatmap dataset={dataset} cells={cells} mode={mode} contrast={contrast} highlightBlock={dataset.biclusterBlock} />
          </div>
        </div>
      </div>

      <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4">
        {miniViews.map(({ mode: m, cells: c, info: i }) => (
          <button
            key={m}
            onClick={() => onMode(m)}
            className="border-3 border-black bg-white p-3 text-left"
            style={{
              outline: mode === m ? `3px solid ${dataset.theme.accent}` : undefined,
              boxShadow: mode === m ? `4px 4px 0 ${dataset.theme.accent}` : "2px 2px 0 #0A0A0A",
            }}
          >
            <p className="font-mono text-[9px] font-bold uppercase text-black/40">{i.tag}</p>
            <div className="mt-2 flex justify-center">
              <Heatmap dataset={dataset} cells={c} mode={m} contrast={contrast} cellSize={14} showLabels={false} compact />
            </div>
          </button>
        ))}
      </div>

      <p className="text-center text-xs text-black/40">
        Full-size dataset — switch to <strong>Learn</strong> tab for the step-by-step 4×4 walkthrough.
      </p>
    </>
  );
}
