"use client";

import type { ReactNode } from "react";

type Props = {
  children: ReactNode;
  accent?: string;
};

/** Single concise explanation block per step — avoids scattered text */
export function StepBrief({ children, accent = "#0A0A0A" }: Props) {
  return (
    <div
      className="readable rounded-none border-l-4 bg-white px-4 py-3 md:px-5 md:py-4"
      style={{ borderColor: accent, backgroundColor: `${accent}0A` }}
    >
      {children}
    </div>
  );
}
