export type DistanceTerm = {
  index: number;
  label: string;
  a: number;
  b: number;
  diff: number;
  squared: number;
};

export function euclideanDistance(a: number[], b: number[]): number {
  let sum = 0;
  for (let i = 0; i < a.length; i++) {
    sum += (a[i] - b[i]) ** 2;
  }
  return Math.sqrt(sum);
}

export function euclideanBreakdown(
  a: number[],
  b: number[],
  labels: string[],
): { distance: number; terms: DistanceTerm[] } {
  const terms: DistanceTerm[] = a.map((val, i) => {
    const diff = val - b[i];
    return {
      index: i,
      label: labels[i] ?? `dim ${i + 1}`,
      a: val,
      b: b[i],
      diff,
      squared: diff ** 2,
    };
  });
  const sumSq = terms.reduce((s, t) => s + t.squared, 0);
  return { distance: Math.sqrt(sumSq), terms };
}

export function buildDistanceMatrix(vectors: number[][]): number[][] {
  const n = vectors.length;
  return Array.from({ length: n }, (_, i) =>
    Array.from({ length: n }, (_, j) =>
      i === j ? 0 : euclideanDistance(vectors[i], vectors[j]),
    ),
  );
}

export function distanceLabel(d: number): "very close" | "close" | "far" | "very far" {
  if (d < 2) return "very close";
  if (d < 4) return "close";
  if (d < 6) return "far";
  return "very far";
}

export function normalizeRating(v: number, min = 1, max = 5): number {
  return (v - min) / (max - min);
}
